using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient();

// --- Instantiate the tools ---
var researchTools = new ResearchTools();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Given a topic, you:
        1. Search the web for relevant information using the SearchWeb tool.
        2. Save important findings using the TakeNote tool with a short key and the content.
        3. Perform multiple searches to cover different aspects of the topic.
        4. When you have gathered enough information, review your notes with GetNotes,
           then produce a well-structured summary with key findings and source URLs.
        Always cite sources. Be thorough — make at least 3 searches on different sub-topics.
        """,
    name: "ResearchAgent",
    description: "Researches a topic by searching the web and summarizing findings",
    tools: tools);

// --- Get the research topic ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent             ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim() ?? "";
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided. Exiting.");
    return 1;
}

Console.WriteLine($"\nResearching: {topic}\n");

// --- Run the agent with streaming output ---
var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// --- Print collected notes ---
var notes = researchTools.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine("\n── Collected Research Notes ──");
    foreach (var (key, content) in notes)
    {
        Console.WriteLine($"\n[{key}]");
        Console.WriteLine(content);
    }
}

return 0;

// =============================================================================
// Tool implementations
// =============================================================================
sealed class ResearchTools
{
    private readonly Dictionary<string, string> _notes = new(StringComparer.OrdinalIgnoreCase);
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    /// <summary>Searches the web for information on a query and returns relevant snippets.</summary>
    [Description("Searches the web for information on a query. Returns text snippets from the results page.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  🔍 Searching: {query}");
        Console.ResetColor();

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

            var html = await _http.GetStringAsync(url);

            // Extract text content from the HTML response
            var text = StripHtml(html);

            // Truncate to a reasonable size for the LLM context
            const int maxLen = 4000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n[... truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "No results found."
                : $"Search results for '{query}':\n\n{text}";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    /// <summary>Saves a research note with a key for later reference.</summary>
    [Description("Saves a research note. Use a short descriptive key and the content to remember.")]
    public string TakeNote(
        [Description("A short key/title for this note")] string key,
        [Description("The content of the note")] string content)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note saved: {key}");
        Console.ResetColor();

        _notes[key] = content;
        return $"Note '{key}' saved successfully.";
    }

    /// <summary>Returns all previously saved research notes.</summary>
    [Description("Retrieves all saved research notes. Use this to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        foreach (var (key, content) in _notes)
        {
            sb.AppendLine($"## {key}");
            sb.AppendLine(content);
            sb.AppendLine();
        }
        return sb.ToString();
    }

    public IReadOnlyList<(string Key, string Content)> GetAllNotes()
        => _notes.Select(kv => (kv.Key, kv.Value)).ToList();

    private static string StripHtml(string html)
    {
        var sb = new StringBuilder(html.Length);
        bool inTag = false;
        bool lastWasSpace = false;

        foreach (var ch in html)
        {
            if (ch == '<') { inTag = true; continue; }
            if (ch == '>') { inTag = false; continue; }
            if (inTag) continue;

            if (char.IsWhiteSpace(ch))
            {
                if (!lastWasSpace) sb.Append(' ');
                lastWasSpace = true;
            }
            else
            {
                sb.Append(ch);
                lastWasSpace = false;
            }
        }

        return System.Net.WebUtility.HtmlDecode(sb.ToString().Trim());
    }
}

