 using System.ComponentModel;
 using System.Text;
 using Microsoft.Extensions.AI;
 using Microsoft.Agents.AI;
 using OpenAI;

 // --- Configuration ---
 var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
     ?? throw new InvalidOperationException(
         "Set the OPENAI_API_KEY environment variable before running.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

 // --- Build the IChatClient via MEAI abstraction ---
 IChatClient chatClient = new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient();

 // --- Instantiate the tools ---
 var researchTools = new ResearchTools();

 var tools = new AITool[]
 {
     AIFunctionFactory.Create(researchTools.SearchWeb),
     AIFunctionFactory.Create(researchTools.TakeNote),
     AIFunctionFactory.Create(researchTools.GetNotes),
 };

 // --- Create the agent ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research agent. Given a topic, you:
         1. Search the web for relevant information using the SearchWeb tool.
         2. Save important findings using the TakeNote tool with a short key and the content.
         3. Perform multiple searches to cover different aspects of the topic.
         4. When you have gathered enough information, review your notes with GetNotes,
            then produce a well-structured summary with key findings and source URLs.
         Always cite sources. Be thorough — make at least 3 searches on different sub-topics.
         """,
     name: "ResearchAgent",
     description: "Researches a topic by searching the web and summarizing findings",
     tools: tools);

 // --- Get the research topic ---
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║        AI Research Agent             ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine();

 string topic;
 if (args.Length > 0)
 {
     topic = string.Join(' ', args);
 }
 else
 {
     Console.Write("Enter a research topic: ");
     topic = Console.ReadLine()?.Trim() ?? "";
 }

 if (string.IsNullOrWhiteSpace(topic))
 {
     Console.Error.WriteLine("No topic provided. Exiting.");
     return 1;
 }

 Console.WriteLine($"\nResearching: {topic}\n");

 // --- Run the agent with streaming output ---
 var session = await agent.CreateSessionAsync();

 var runOptions = new ChatClientAgentRunOptions
 {
     ChatOptions = new ChatOptions
     {
         Temperature = 0f,
         MaxOutputTokens = 4096,
     },
 };

 await foreach (var update in agent.RunStreamingAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session,
     runOptions))
 {
     if (!string.IsNullOrEmpty(update.Text))
     {
         Console.Write(update.Text);
     }
 }

 Console.WriteLine();

